1	// MHPCO Claim Office - Policy quoting and claim processing system
2	
3	const ITEM_TYPE_PREMIUMS: Record<string, number> = {
4	  Sword: 50,
5	  Amulet: 100,
6	  Staff: 75,
7	  Potion: 60,
8	};
9	
10	const FIRST_INSURANCE_SURCHARGE = 1.1;
11	const LOYALTY_DISCOUNT = 0.8; // -20% discount for 2+ years
12	const CURSED_ITEM_SURCHARGE = 1.5;
13	
14	export interface Item {
15	  type: string;
16	  insuranceModifier?: string;
17	  yearsInsured?: number;
18	  cursed?: boolean;
19	}
20	
21	const applyModifier = (premium: number, shouldApply: boolean, multiplier: number): number => {
22	  return shouldApply ? premium * multiplier : premium;
23	};
24	
25	const applyFirstInsuranceSurcharge = (premium: number, modifier?: string): number => {
26	  return applyModifier(premium, modifier === "first", FIRST_INSURANCE_SURCHARGE);
27	};
28	
29	const applyLoyaltyDiscount = (premium: number, yearsInsured?: number): number => {
30	  return applyModifier(premium, yearsInsured !== undefined && yearsInsured >= 2, LOYALTY_DISCOUNT);
31	};
32	
33	const applyCursedSurcharge = (premium: number, cursed?: boolean): number => {
34	  return applyModifier(premium, cursed === true, CURSED_ITEM_SURCHARGE);
35	};
36	
37	export function quotePolicy(items: Item[]): number {
38	  const total = items.reduce((sum, item) => {
39	    const basePremium = ITEM_TYPE_PREMIUMS[item.type] ?? 0;
40	    const modifiedPremium = applyFirstInsuranceSurcharge(basePremium, item.insuranceModifier);
41	    const discountedPremium = applyLoyaltyDiscount(modifiedPremium, item.yearsInsured);
42	    const cursedPremium = applyCursedSurcharge(discountedPremium, item.cursed);
43	    return sum + cursedPremium;
44	  }, 0);
45	  return Math.round(total);
46	}
47	
48	export function quoteComponent(items: Item[]): number {
49	  return items.length === 3 ? 60 : 25;
50	}
51	
52	export function processClaim(): number {
53	  throw new Error("Not implemented");
54	}
